// PaperClaw local web UI for Pinokio.
// Calls https://p2pclaw-mcp-server-production-ac1c.up.railway.app/paperclaw/generate
const http = require('http');
const https = require('https');
const fs = require('fs');
const path = require('path');
const { URL } = require('url');
const API = process.env.PAPERCLAW_API || 'https://p2pclaw-mcp-server-production-ac1c.up.railway.app';
const PORT = process.env.PORT ? parseInt(process.env.PORT, 10) : 7860;
function postJSON(url, body) {
  return new Promise((resolve, reject) => {
    const u = new URL(url);
    const tr = u.protocol === 'https:' ? https : http;
    const payload = Buffer.from(JSON.stringify(body), 'utf8');
    const req = tr.request({ method: 'POST', hostname: u.hostname, port: u.port || (u.protocol === 'https:' ? 443 : 80), path: u.pathname + u.search, headers: { 'Content-Type': 'application/json', 'Content-Length': payload.length }, timeout: 120000 }, (res) => {
      const chunks = []; res.on('data', (c) => chunks.push(c));
      res.on('end', () => { const raw = Buffer.concat(chunks).toString('utf8'); try { resolve(JSON.parse(raw)); } catch { reject(new Error('Malformed response: ' + raw.slice(0, 200))); } });
    });
    req.on('error', reject); req.on('timeout', () => { req.destroy(); reject(new Error('Timeout')); });
    req.write(payload); req.end();
  });
}
const UI = `<!doctype html><html><head><meta charset=\"utf-8\"/><title>PaperClaw</title><link rel=\"icon\" href=\"data:,\">
<style>body{margin:0;background:#0c0c0d;color:#f5f0eb;font:14px/1.5 ui-monospace,Menlo,Consolas,monospace;padding:32px;max-width:760px;margin:auto}h1{color:#ff4e1a;letter-spacing:.05em;font-weight:800}textarea,input{width:100%;padding:10px 12px;background:#1a1a1c;color:#f5f0eb;border:1px solid #ff4e1a55;border-radius:6px;font:13px/1.5 inherit;margin:6px 0 14px;box-sizing:border-box}button{background:#ff4e1a;color:#fff;border:0;padding:10px 18px;border-radius:6px;font-weight:700;cursor:pointer;font:13px inherit}button:disabled{opacity:.5}.result{margin-top:18px;padding:14px;background:#1a1a1c;border-left:3px solid #ff4e1a;border-radius:4px;word-break:break-all}a{color:#ff7020}.log{color:#52504e;font-size:12px;margin-top:8px;white-space:pre-wrap}</style></head><body>
<h1>PaperClaw</h1><p>Describe your project. We write the paper, publish it on p2pclaw.com, hand you the link.</p>
<textarea id=desc rows=4 placeholder=\"A peer-to-peer reputation system using verifiable delay functions…\"></textarea>
<label>Author</label><input id=author placeholder=\"Ada Lovelace\">
<label>Tags (comma-separated, optional)</label><input id=tags placeholder=\"p2p, crypto\">
<button id=go>Publish paper</button>
<div id=out class=result style=\"display:none\"></div>
<div id=log class=log></div>
<script>
const $=(s)=>document.querySelector(s);
$('#go').onclick = async () => {
  const description = $('#desc').value.trim();
  if (description.length < 30) { $('#log').textContent='Description must be at least 30 chars.'; return; }
  $('#go').disabled = true; $('#out').style.display='none'; $('#log').textContent='Asking your P2PCLAW agent… (usually ~30s)';
  try {
    const r = await fetch('/api/generate', { method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({ description, author: $('#author').value.trim() || 'Anonymous Researcher', tags: $('#tags').value.split(',').map(s=>s.trim()).filter(Boolean) }) });
    const data = await r.json();
    if (!data.success) { $('#log').textContent='Error: '+(data.message||data.error); $('#go').disabled=false; return; }
    $('#out').style.display='block';
    $('#out').innerHTML = '<b>Published ✓</b><br>Title: '+data.title+'<br>Words: '+data.wordCount+'<br>Via: '+(data.llm?.provider||'?')+'<br><br><a target=_blank href=\"'+data.url+'\">'+data.url+'</a> · <a target=_blank href=\"'+data.url+'#print\">Save as PDF</a>';
    $('#log').textContent='';
  } catch (e) { $('#log').textContent='Fatal: '+e.message; }
  $('#go').disabled = false;
};
</script></body></html>`;
const server = http.createServer(async (req, res) => {
  if (req.method === 'GET' && (req.url === '/' || req.url === '/index.html')) {
    res.writeHead(200, { 'Content-Type': 'text/html; charset=utf-8' }); res.end(UI); return;
  }
  if (req.method === 'POST' && req.url === '/api/generate') {
    const chunks = []; req.on('data', (c) => chunks.push(c));
    req.on('end', async () => {
      try {
        const body = JSON.parse(Buffer.concat(chunks).toString('utf8'));
        const resp = await postJSON(`${API}/paperclaw/generate`, { ...body, client: 'paperclaw-pinokio' });
        res.writeHead(200, { 'Content-Type': 'application/json' }); res.end(JSON.stringify(resp));
      } catch (e) { res.writeHead(500, { 'Content-Type': 'application/json' }); res.end(JSON.stringify({ success: false, error: 'proxy_error', message: e.message })); }
    });
    return;
  }
  res.writeHead(404); res.end('not found');
});
server.listen(PORT, '127.0.0.1', () => { console.log('PaperClaw UI → http://127.0.0.1:' + PORT); });
